import pygame
import random
from enum import Enum
from dataclasses import dataclass
from typing import List, Tuple, Optional, Dict

# Enum and Data Classes for Colors, Gems and Tetrominos
class Color(Enum):
    CYAN = (0, 255, 255)
    BLUE = (0, 0, 255)
    ORANGE = (255, 165, 0)
    YELLOW = (255, 255, 0)
    GREEN = (0, 255, 0)
    PURPLE = (128, 0, 128)
    RED = (255, 0, 0)

@dataclass
class GemCell:
    color: Color

@dataclass
class Tetromino:
    shape_id: str
    rotations: List[List[Tuple[int, int]]]
    color: Color

TETROMINO_SHAPES: Dict[str, Tetromino] = {
