        shape_id='I',
        color=Color.CYAN,
        rotations=[
            [(0,1),(1,1),(2,1),(3,1)],
            [(2,0),(2,1),(2,2),(2,3)],
            [(0,2),(1,2),(2,2),(3,2)],
            [(1,0),(1,1),(1,2),(1,3)],
        ]
    ),
    'O': Tetromino(
        shape_id='O',
        color=Color.YELLOW,
        rotations=[[(1,0),(2,0),(1,1),(2,1)]]
    ),
