        shape_id='T',
        color=Color.PURPLE,
        rotations=[
            [(1,0),(0,1),(1,1),(2,1)],
            [(1,0),(1,1),(2,1),(1,2)],
            [(0,1),(1,1),(2,1),(1,2)],
